diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index fc284bc61cce..77bc56bbb6c5 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1134,36 +1134,70 @@ static bool MulWillOverflow(APInt &C0, APInt &C1, bool IsSigned) {

 // Simplifies X % C0 + (( X / C0 ) % C1) * C0 to X % (C0 * C1), where (C0 * C1)
 // does not overflow.
+
 Value *InstCombinerImpl::SimplifyAddWithRemainder(BinaryOperator &I) {
   Value *LHS = I.getOperand(0), *RHS = I.getOperand(1);
   Value *X, *MulOpV;
   APInt C0, MulOpC;
   bool IsSigned;
-  // Match I = X % C0 + MulOpV * C0
-  if (((MatchRem(LHS, X, C0, IsSigned) && MatchMul(RHS, MulOpV, MulOpC)) ||
-       (MatchRem(RHS, X, C0, IsSigned) && MatchMul(LHS, MulOpV, MulOpC))) &&
-      C0 == MulOpC) {
-    Value *RemOpV;
-    APInt C1;
-    bool Rem2IsSigned;
-    // Match MulOpC = RemOpV % C1
-    if (MatchRem(MulOpV, RemOpV, C1, Rem2IsSigned) &&
-        IsSigned == Rem2IsSigned) {
-      Value *DivOpV;
-      APInt DivOpC;
-      // Match RemOpV = X / C0
-      if (MatchDiv(RemOpV, DivOpV, DivOpC, IsSigned) && X == DivOpV &&
-          C0 == DivOpC && !MulWillOverflow(C0, C1, IsSigned)) {
-        Value *NewDivisor = ConstantInt::get(X->getType(), C0 * C1);
-        return IsSigned ? Builder.CreateSRem(X, NewDivisor, "srem")
-                        : Builder.CreateURem(X, NewDivisor, "urem");
+
+  // Helper to match multiplication by constant (mul or shl)
+  auto MatchMulOrShl = [&](Value *V, Value *&Op, APInt &C) -> bool {
+    if (MatchMul(V, Op, C))
+      return true;
+    // shl by constant is equivalent to mul by 2^N
+    const APInt *ShlC;
+    if (match(V, m_Shl(m_Value(Op), m_APInt(ShlC)))) {
+      C = APInt(ShlC->getBitWidth(), 1) << *ShlC;
+      return true;
+    }
+    return false;
+  };
+
+  // Match I = X % C0 + MulOpV * MulOpC
+  if ((MatchRem(LHS, X, C0, IsSigned) && MatchMulOrShl(RHS, MulOpV, MulOpC)) ||
+      (MatchRem(RHS, X, C0, IsSigned) && MatchMulOrShl(LHS, MulOpV, MulOpC))) {
+    // Existing case: C0 == MulOpC and MulOpV is a remainder
+    if (C0 == MulOpC) {
+      Value *RemOpV;
+      APInt C1;
+      bool Rem2IsSigned;
+      // Match MulOpC = RemOpV % C1
+      if (MatchRem(MulOpV, RemOpV, C1, Rem2IsSigned) &&
+          IsSigned == Rem2IsSigned) {
+        Value *DivOpV;
+        APInt DivOpC;
+        // Match RemOpV = X / C0
+        if (MatchDiv(RemOpV, DivOpV, DivOpC, IsSigned) && X == DivOpV &&
+            C0 == DivOpC && !MulWillOverflow(C0, C1, IsSigned)) {
+          Value *NewDivisor = ConstantInt::get(X->getType(), C0 * C1);
+          return IsSigned ? Builder.CreateSRem(X, NewDivisor, "srem")
+                          : Builder.CreateURem(X, NewDivisor, "urem");
+        }
       }
     }
+    // New case: MulOpV = X / C0, where MulOpC may differ from C0
+    // Transform: X % C0 + (X / C0) * MulOpC -> X + (X / C0) * (MulOpC - C0)
+    Value *DivOpV;
+    APInt DivOpC;
+    if (MatchDiv(MulOpV, DivOpV, DivOpC, IsSigned) && X == DivOpV &&
+        C0 == DivOpC && MulOpC.uge(C0)) {
+      APInt NewMulC = MulOpC - C0;
+      Value *NewMul;
+      // For unsigned, nuw is valid when NewMulC <= C0
+      if (!IsSigned && NewMulC.ule(C0)) {
+        NewMul = Builder.CreateNUWMul(MulOpV, ConstantInt::get(X->getType(), NewMulC));
+      } else {
+        NewMul = Builder.CreateMul(MulOpV, ConstantInt::get(X->getType(), NewMulC));
+      }
+      return Builder.CreateAdd(X, NewMul);
+    }
   }

   return nullptr;
 }

+
 /// Fold
 ///   (1 << NBits) - 1
 /// Into:
